import re

def password_pattern_search(documents):
    common_passwords = ['123456', 'password', 'admin', 'qwerty', 'abc123', 'iloveyou']
    results = {}
    for doc in documents:
        for password in common_passwords:
            if re.search(password, doc):
                if password in results:
                    results[password] += 1
                else:
                    results[password] = 1
    return results
